using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int x;
void f(int x)
{
	if (x == 1)
	{
		printf("2(0)");
		return;
	}
	if (x == 2)
	{
		printf("2");
		return;
	}
	printf("2");
	if (int(log2(x)) != 1)
	{
		printf("(");
		f(int(log2(x)));
		printf(")");
	}
	if (x > (1 << int(log2(x))))
	{
		printf("+");
		f(x - (1 << int(log2(x))));
	}
}
int main(void)
{
	x = read();
	f(x);
	return false;
}
